sql:
SELECT total_pay_benefits
FROM total_compensation
WHERE employee_id = 0 AND year = '2014';

SELECT benefit_type
FROM benefits_enrollment
WHERE employee_id = 0 AND status = 'active';

SELECT COUNT(*) AS active_contract_count
  FROM contract_details
  WHERE status = 'active';

external_knowledge:
- 'seasoned veterans' refers to active, full-time employees who have been with the company for more than 5 years; 
- 'surpassed the golden benchmark' means having a total compensation (total pay + total benefits) exceeding $50,000; 
- 'on the payroll' implies being an active employee; 
- 'this year' refers to the current year as determined by `strftime('%Y', 'now')`.
